6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a simple AXI master. Simple means: It does not
11	-- support any unaligned reads/writes and it does not do any width conversions.
12	-- It just executes the transfers requested and splits them into multiple AXI
13	-- transactions in order to not burst over 4k boundaries and respect the maximum
14	-- transaction size.
15	--
16	-- Documentation:
17	-- https://github.com/open-logic/open-logic/blob/main/doc/axi/olo_axi_master_simple.md
18	--
19	-- Note: The link points to the documentation of the latest release. If you
20	--       use an older version, the documentation might not match the code.
21	
22	---------------------------------------------------------------------------------------------------
23	-- Libraries
24	---------------------------------------------------------------------------------------------------
25	library ieee;
26	    use ieee.std_logic_1164.all;
27	    use ieee.numeric_std.all;
28	
29	library work;
30	    use work.olo_base_pkg_math.all;
31	    use work.olo_base_pkg_logic.all;
32	    use work.olo_base_pkg_string.all;
33	    use work.olo_axi_pkg_protocol.all;
34	
35	---------------------------------------------------------------------------------------------------
36	-- Entity
37	---------------------------------------------------------------------------------------------------
38	entity olo_axi_master_simple is
39	    generic (
40	        -- AXI Configuration
41	        AxiAddrWidth_g              : positive range 12 to 64  := 32;
42	        AxiDataWidth_g              : positive range 8 to 1024 := 32;
43	        AxiMaxBeats_g               : positive range 1 to 256  := 256;
44	        AxiMaxOpenTransactions_g    : positive range 1 to 8    := 8;
45	        -- User Configuration
46	        UserTransactionSizeBits_g   : positive                 := 24;
47	        DataFifoDepth_g             : positive                 := 1024;
48	        ImplRead_g                  : boolean                  := true;
49	        ImplWrite_g                 : boolean                  := true;
50	        RamBehavior_g               : string                   := "RBW"
51	    );
52	    port (
53	        -- Control Signals
54	        Clk             : in    std_logic;
55	        Rst             : in    std_logic;
56	        -- User Command Interface
57	        CmdWr_Addr      : in    std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
58	        CmdWr_Size      : in    std_logic_vector(UserTransactionSizeBits_g - 1 downto 0) := (others => '0');
59	        CmdWr_LowLat    : in    std_logic                                                := '0';
60	        CmdWr_Valid     : in    std_logic                                                := '0';
61	        CmdWr_Ready     : out   std_logic;
62	        -- User Command Interface
63	        CmdRd_Addr      : in    std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
64	        CmdRd_Size      : in    std_logic_vector(UserTransactionSizeBits_g - 1 downto 0) := (others => '0');
65	        CmdRd_LowLat    : in    std_logic                                                := '0';
66	        CmdRd_Valid     : in    std_logic                                                := '0';
67	        CmdRd_Ready     : out   std_logic;
68	        -- Write Data
69	        Wr_Data         : in    std_logic_vector(AxiDataWidth_g - 1 downto 0)            := (others => '0');
70	        Wr_Be           : in    std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0)        := (others => '0');
71	        Wr_Valid        : in    std_logic                                                := '0';
72	        Wr_Ready        : out   std_logic;
73	        -- Read Data
74	        Rd_Data         : out   std_logic_vector(AxiDataWidth_g - 1 downto 0);
75	        Rd_Last         : out   std_logic;
76	        Rd_Valid        : out   std_logic;
77	        Rd_Ready        : in    std_logic                                                := '1';
78	        -- Response
79	        Wr_Done         : out   std_logic;
80	        Wr_Error        : out   std_logic;
81	        Rd_Done         : out   std_logic;
82	        Rd_Error        : out   std_logic;
83	        -- AXI Address Write Channel
84	        M_Axi_AwAddr    : out   std_logic_vector(AxiAddrWidth_g - 1 downto 0);
85	        M_Axi_AwLen     : out   std_logic_vector(7 downto 0);
86	        M_Axi_AwSize    : out   std_logic_vector(2 downto 0);
87	        M_Axi_AwBurst   : out   std_logic_vector(1 downto 0);
88	        M_Axi_AwLock    : out   std_logic;
89	        M_Axi_AwCache   : out   std_logic_vector(3 downto 0);
90	        M_Axi_AwProt    : out   std_logic_vector(2 downto 0);
91	        M_Axi_AwValid   : out   std_logic;
92	        M_Axi_AwReady   : in    std_logic                                                := '0';
93	        -- AXI Write Data Channel
94	        M_Axi_WData     : out   std_logic_vector(AxiDataWidth_g - 1 downto 0);
95	        M_Axi_WStrb     : out   std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0);
96	        M_Axi_WLast     : out   std_logic;
97	        M_Axi_WValid    : out   std_logic;
98	        M_Axi_WReady    : in    std_logic                                                := '0';
99	        -- AXI Write Response Channel
100	        M_Axi_BResp     : in    std_logic_vector(1 downto 0)                             := (others => '0');
101	        M_Axi_BValid    : in    std_logic                                                := '0';
102	        M_Axi_BReady    : out   std_logic;
103	        -- AXI Read Address Channel
104	        M_Axi_ArAddr    : out   std_logic_vector(AxiAddrWidth_g - 1 downto 0);
105	        M_Axi_ArLen     : out   std_logic_vector(7 downto 0);
106	        M_Axi_ArSize    : out   std_logic_vector(2 downto 0);
107	        M_Axi_ArBurst   : out   std_logic_vector(1 downto 0);
108	        M_Axi_ArLock    : out   std_logic;
109	        M_Axi_ArCache   : out   std_logic_vector(3 downto 0);
110	        M_Axi_ArProt    : out   std_logic_vector(2 downto 0);
111	        M_Axi_ArValid   : out   std_logic;
112	        M_Axi_ArReady   : in    std_logic                                                := '0';
113	        -- AXI Read Data Channel
114	        M_Axi_RData     : in    std_logic_vector(AxiDataWidth_g - 1 downto 0)            := (others => '0');
115	        M_Axi_RResp     : in    std_logic_vector(1 downto 0)                             := (others => '0');
116	        M_Axi_RLast     : in    std_logic                                                := '0';
117	        M_Axi_RValid    : in    std_logic                                                := '0';
118	        M_Axi_RReady    : out   std_logic
119	    );
120	end entity;
121	
122	---------------------------------------------------------------------------------------------------
123	-- Architecture
124	---------------------------------------------------------------------------------------------------
125	architecture rtl of olo_axi_master_simple is
126	
127	    -- *** Constants ***
128	    constant EntityName_c     : string  := "olo_axi_master_simple";
129	    constant UnusedAddrBits_c : natural := log2(AxiDataWidth_g / 8);
130	
131	    constant BeatsBits_c     : natural := log2ceil(AxiMaxBeats_g + 1);
132	    constant MaxBeatsNoCmd_c : natural := max(AxiMaxBeats_g * AxiMaxOpenTransactions_g, DataFifoDepth_g);
133	
134	    -- *** Type Definitions ***
135	    type WriteTfGen_t is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
136	    type ReadTfGen_t is (Idle_s, MaxCalc_s, GenTf_s, WriteTf_s);
137	    type AwFsm_t is (Idle_s, Wait_s);
138	    type ArFsm_t is (Idle_s, Wait_s);
139	    type WrFsm_t is (Idle_s, NonLast_s, Last_s);
140	
141	    -- *** Functions ***
142	    function addrMasked (Addr : in std_logic_vector) return std_logic_vector is
143	        variable Masked_v : std_logic_vector(Addr'range);
144	    begin
145	        Masked_v                                := Addr;
146	        Masked_v(UnusedAddrBits_c - 1 downto 0) := (others => '0');
147	        return Masked_v;
148	    end function;
149	
150	    -- *** Two Process Record ***
151	    type TwoProcess_r is record
152	        -- *** Write Related Registers ***
153	        -- Command Interface
154	        CmdWr_Ready     : std_logic;
155	        Wr_Error        : std_logic;
156	        Wr_Done         : std_logic;
157	        -- Generate Write Transactions
158	        WriteTfGenState : WriteTfGen_t;
159	        WrAddr          : unsigned(CmdWr_Addr'range);
160	        WrBeats         : unsigned(CmdWr_Size'range);
161	        WrLowLat        : std_logic;
162	        WrMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
163	        WrTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
164	        WrTfVld         : std_logic;
165	        WrTfIsLast      : std_logic;
166	        -- Execute Aw Commands
167	        AwFsm           : AwFsm_t;
168	        AwFsmRdy        : std_logic;
169	        AwCmdSent       : std_logic;
170	        AwCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
171	        AwCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- AwCmdSize-1 for timing optimization reasons
172	        WDataFifoWrite  : std_logic;
173	        -- Execute W Data
174	        WFsm            : WrFsm_t;
175	        WDataFifoRd     : std_logic;
176	        WDataEna        : std_logic;
177	        WDataBeats      : unsigned(BeatsBits_c - 1 downto 0);
178	        -- Write Response
179	        WrRespError     : std_logic;
180	        -- Write General
181	        WrOpenTrans     : integer range -1 to AxiMaxOpenTransactions_g;
182	        WrBeatsNoCmd    : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
183	        -- AXI Signals
184	        M_Axi_AwAddr    : std_logic_vector(M_Axi_AwAddr'range);
185	        M_Axi_AwLen     : std_logic_vector(M_Axi_AwLen'range);
186	        M_Axi_AwValid   : std_logic;
187	        M_Axi_WLast     : std_logic;
188	
189	        -- *** Read Related Registers ***
190	        -- Command Interface
191	        CmdRd_Ready     : std_logic;
192	        Rd_Error        : std_logic;
193	        Rd_Done         : std_logic;
194	        -- Generate Read Transactions
195	        ReadTfGenState  : ReadTfGen_t;
196	        RdAddr          : unsigned(CmdRd_Addr'range);
197	        RdBeats         : unsigned(CmdRd_Size'range);
198	        RdLowLat        : std_logic;
199	        RdMaxBeats      : unsigned(BeatsBits_c - 1 downto 0);
200	        RdTfBeats       : unsigned(BeatsBits_c - 1 downto 0);
201	        RdTfVld         : std_logic;
202	        RdTfIsLast      : std_logic;
203	        -- Execute Ar Commands
204	        ArFsm           : ArFsm_t;
205	        ArFsmRdy        : std_logic;
206	        ArCmdSent       : std_logic;
207	        ArCmdSize       : unsigned(BeatsBits_c - 1 downto 0);
208	        ArCmdSizeMin1   : unsigned(BeatsBits_c - 1 downto 0); -- ArCmdSize-1 for timing optimization reasons
209	        RDataFifoRead   : std_logic;
210	        -- Write Response
211	        RdRespError     : std_logic;
212	        -- Read General
213	        RdOpenTrans     : unsigned(log2ceil(AxiMaxOpenTransactions_g + 1) - 1 downto 0);
214	        RdFifoSpaceFree : signed(log2ceil(MaxBeatsNoCmd_c + 1) downto 0);
215	        -- AXI Signals
216	        M_Axi_ArAddr    : std_logic_vector(M_Axi_ArAddr'range);
217	        M_Axi_ArLen     : std_logic_vector(M_Axi_ArLen'range);
218	        M_Axi_ArValid   : std_logic;
219	    end record;
220	
221	    signal r, r_next : TwoProcess_r;
222	
223	    -- *** Instantiation Signals ***
224	    signal WrDataFifoORdy    : std_logic;
225	    signal WrDataFifoOVld    : std_logic;
226	    signal WrTransFifoInVld  : std_logic;
227	    signal WrTransFifoBeats  : std_logic_vector(BeatsBits_c - 1 downto 0);
228	    signal WrTransFifoOutVld : std_logic;
229	    signal WrRespIsLast      : std_logic;
230	    signal WrRespFifoVld     : std_logic;
231	    signal WrData_Rdy_I      : std_logic;
232	    signal RdTransFifoInVld  : std_logic;
233	    signal RdRespIsLast      : std_logic;
234	    signal RdRespFifoVld     : std_logic;
235	    signal RdDat_Vld_I       : std_logic;
236	    signal RdRespLast        : std_logic;
237	    signal M_Axi_RReady_I    : std_logic;
238	
239	begin
240	
241	    -- *** Static Assertions ***
242	    assert AxiDataWidth_g mod 8 = 0
243	        report errorMessage(EntityName_c, "AxiDataWidth_g must be a multiple of 8")
244	        severity failure;
245	    assert isPower2(AxiDataWidth_g/8)
246	        report errorMessage(EntityName_c, "AxiDataWidth_g must be 2^X bytes")
247	        severity failure;
248	    assert UserTransactionSizeBits_g < AxiAddrWidth_g-log2(AxiDataWidth_g/8)
249	        report errorMessage(EntityName_c, "UserTransactionSizeBits_g must be smaller than AxiAddrWidth_g-log2(AxiDataWidth_g/8), see documentation")
250	        severity failure;
251	
252	    -- *** Runtime Assertions ***
253	    -- synthesis translate_off
254	    p_assert : process (Clk) is
255	    begin
256	        if rising_edge(Clk) then
257	            -- Unexpected read response
258	            if ImplRead_g and RdRespLast = '1' then
259	                assert RdRespFifoVld = '1'
260	                    report errorMessage(EntityName_c, "Unexpected Read Response (RdRespFifo Empty)")
261	                    severity error;
262	            end if;
263	            -- Unexpected write response
264	            if ImplWrite_g and M_Axi_BValid = '1' then
265	                assert WrRespFifoVld = '1'
266	                    report errorMessage(EntityName_c, "Unexpected Write Response (WrRespFifo Empty)")
267	                    severity error;
268	            end if;
269	        end if;
270	    end process;
271	
272	    -- synthesis translate_on
273	
274	    -- *** Combinatorial Process ***
275	    p_comb : process (all) is
276	        variable v               : TwoProcess_r;
277	        variable WrMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
278	        variable RdMax4kBeats_v  : unsigned(13 - UnusedAddrBits_c downto 0);
279	        variable Stdlv9Bit_v     : std_logic_vector(8 downto 0);
280	        variable WDataTransfer_v : boolean;
281	        variable StartWBurst_v   : boolean := true;
282	    begin
283	        -- *** Keep two process variables stable ***
284	        v := r;
285	
286	        -- *** Write Related Code ***
287	        if ImplWrite_g then
288	
289	            -- Default Value
290	            WrMax4kBeats_v := (others => '0');
291	
292	            -- Write Transfer Generation FSM
293	            case r.WriteTfGenState is
294	                when Idle_s =>
295	                    v.CmdWr_Ready := '1';
296	                    if (r.CmdWr_Ready = '1') and (CmdWr_Valid = '1') then
297	                        v.CmdWr_Ready     := '0';
298	                        v.WrAddr          := unsigned(addrMasked(CmdWr_Addr));
299	                        v.WrBeats         := unsigned(CmdWr_Size);
300	                        v.WrLowLat        := CmdWr_LowLat;
301	                        v.WriteTfGenState := MaxCalc_s;
302	                    end if;
303	
304	                when MaxCalc_s =>
305	                    WrMax4kBeats_v := resize(unsigned('0' & not r.WrAddr(11 downto UnusedAddrBits_c)) + 1, WrMax4kBeats_v'length);
306	                    if WrMax4kBeats_v > AxiMaxBeats_g then
307	                        v.WrMaxBeats := to_unsigned(AxiMaxBeats_g, BeatsBits_c);
308	                    else
309	                        v.WrMaxBeats := WrMax4kBeats_v(BeatsBits_c - 1 downto 0);
310	                    end if;
311	                    v.WriteTfGenState := GenTf_s;
312	
313	                when GenTf_s =>
314	                    if (r.WrMaxBeats < r.WrBeats) then
315	                        v.WrTfBeats  := r.WrMaxBeats;
316	                        v.WrTfIsLast := '0';
317	                    else
318	                        v.WrTfBeats  := r.WrBeats(BeatsBits_c - 1 downto 0);
319	                        v.WrTfIsLast := '1';
320	                    end if;
321	                    v.WrTfVld         := '1';
322	                    v.WriteTfGenState := WriteTf_s;
323	
324	                when WriteTf_s =>
325	                    if (r.WrTfVld = '1') and (r.AwFsmRdy = '1') then
326	                        v.WrTfVld := '0';
327	                        v.WrBeats := r.WrBeats - r.WrTfBeats;
328	                        v.WrAddr  := r.WrAddr + resize(2**UnusedAddrBits_c * r.WrTfBeats, v.WrAddr'length);
329	                        if r.WrTfIsLast = '1' then
330	                            v.WriteTfGenState := Idle_s;
331	                        else
332	                            v.WriteTfGenState := MaxCalc_s;
333	                        end if;
334	                    end if;
335	
336	                -- coverage off
337	                when others => null; -- unreachable code
338	                -- coverage on
339	
340	            end case;
341	
342	            -- ADefault Value
343	            v.AwCmdSent := '0';
344	
345	            -- AW generation FSM
346	            case r.AwFsm is
347	                when Idle_s =>
348	                    if ((r.WrLowLat = '1') or (r.WrBeatsNoCmd >= signed('0' & r.WrTfBeats))) and
349	                       (r.WrOpenTrans < AxiMaxOpenTransactions_g) and (r.WrTfVld = '1') then
350	                        v.AwFsmRdy := '1';
351	                    end if;
352	                    if (r.AwFsmRdy = '1') and (r.WrTfVld = '1') then
353	                        v.AwFsmRdy      := '0';
354	                        v.M_Axi_AwAddr  := std_logic_vector(r.WrAddr);
355	                        Stdlv9Bit_v     := std_logic_vector(resize(r.WrTfBeats - 1, 9));
356	                        v.M_Axi_AwLen   := Stdlv9Bit_v(7 downto 0);
357	                        v.M_Axi_AwValid := '1';
358	                        v.AwFsm         := Wait_s;
359	                        v.AwCmdSent     := '1';
360	                        v.AwCmdSize     := r.WrTfBeats;
361	                        v.AwCmdSizeMin1 := r.WrTfBeats - 1;
362	                    end if;
363	
364	                when Wait_s =>
365	                    if M_Axi_AwReady = '1' then
366	                        v.WrOpenTrans   := r.WrOpenTrans + 1;
367	                        v.M_Axi_AwValid := '0';
368	                        v.AwFsm         := Idle_s;
369	                    end if;
370	
371	                -- coverage off
372	                when others => null; -- unreachable code
373	                -- coverage on
374	
375	            end case;
376	
377	            -- Update counter for FIFO entries that were not yet announced in a command
378	            -- .. Implementation is a bit weird for timing optimization reasons.
379	            -- Use registered WDataFifoWrite: This helps with timing and it does not introduce any risk since
380	            -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
381	            -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
382	            v.WDataFifoWrite := WrData_Rdy_I and Wr_Valid;
383	            if r.AwCmdSent = '1' then
384	                if r.WDataFifoWrite = '1' then
385	                    v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
386	                else
387	                    v.WrBeatsNoCmd := r.WrBeatsNoCmd - signed('0' & r.AwCmdSize);
388	                end if;
389	            elsif r.WDataFifoWrite = '1' then
390	                v.WrBeatsNoCmd := r.WrBeatsNoCmd + 1;
391	            end if;
392	
393	            -- Default Values
394	            WDataTransfer_v := (r.WDataEna = '1') and (WrDataFifoOVld = '1') and (WrDataFifoORdy = '1');
395	            v.WDataFifoRd   := '0';
396	            StartWBurst_v   := false;
397	
398	            -- W generation FSM
399	            case r.WFsm is
400	                when Idle_s =>
401	                    if WrTransFifoOutVld = '1' then
402	                        StartWBurst_v := true;      -- shared code
403	                    end if;
404	
405	                when NonLast_s =>
406	                    if WDataTransfer_v then
407	                        if r.WDataBeats = 2 then
408	                            v.M_Axi_WLast := '1';
409	                            v.WFsm        := Last_s;
410	                        end if;
411	                        v.WDataBeats := r.WDataBeats - 1;
412	                    end if;
413	
414	                when Last_s =>
415	                    if WDataTransfer_v then
416	                        -- Immediately start next transfer
417	                        -- .. WDataFifoRd is checked to leave time for the FIFO to complete the read in case of single cycle transfers
418	                        if (WrTransFifoOutVld = '1') and (r.WDataFifoRd = '0') then
419	                            StartWBurst_v := true;    -- shared code
420	                        -- End of transfer without a next one back-to-back
421	                        else
422	                            v.WDataEna    := '0';
423	                            v.WFsm        := Idle_s;
424	                            v.M_Axi_WLast := '0';
425	                        end if;
426	                    end if;
427	
428	                -- coverage off
429	                when others => null; -- unreachable code
430	                -- coverage on
431	
432	            end case;
433	
434	            -- implementation of shared code
435	            if StartWBurst_v then
436	                v.WDataFifoRd := '1';
437	                v.WDataEna    := '1';
438	                v.WDataBeats  := unsigned(WrTransFifoBeats);
439	                if unsigned(WrTransFifoBeats) = 1 then
440	                    v.M_Axi_WLast := '1';
441	                    v.WFsm        := Last_s;
442	                else
443	                    v.M_Axi_WLast := '0';
444	                    v.WFsm        := NonLast_s;
445	                end if;
446	            end if;
447	
448	            -- Default values
449	            v.Wr_Done  := '0';
450	            v.Wr_Error := '0';
451	
452	            -- W response FSM
453	            if M_Axi_BValid = '1' then
454	                v.WrOpenTrans := v.WrOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
455	                if WrRespIsLast = '1' then
456	                    if (M_Axi_BResp /= AxiResp_Okay_c) then
457	                        v.Wr_Error := '1';
458	                    else
459	                        v.Wr_Error    := r.WrRespError;
460	                        v.Wr_Done     := not r.WrRespError;
461	                        v.WrRespError := '0';
462	                    end if;
463	                elsif M_Axi_BResp /= AxiResp_Okay_c then
464	                    v.WrRespError := '1';
465	                end if;
466	            end if;
467	
468	        end if;
469	
470	        -- *** Read Related Code ***
471	        if ImplRead_g then
472	
473	            -- Default Values
474	            RdMax4kBeats_v := (others => '0');
475	
476	            -- Read generation FSM
477	            case r.ReadTfGenState is
478	                when Idle_s =>
479	                    v.CmdRd_Ready := '1';
480	                    if (r.CmdRd_Ready = '1') and (CmdRd_Valid = '1') then
481	                        v.CmdRd_Ready    := '0';
482	                        v.RdAddr         := unsigned(addrMasked(CmdRd_Addr));
483	                        v.RdBeats        := unsigned(CmdRd_Size);
484	                        v.RdLowLat       := CmdRd_LowLat;
485	                        v.ReadTfGenState := MaxCalc_s;
486	                    end if;
487	
488	                when MaxCalc_s =>
489	                    RdMax4kBeats_v := resize(unsigned('0' & not r.RdAddr(11 downto UnusedAddrBits_c)) + 1, RdMax4kBeats_v'length);
490	                    if RdMax4kBeats_v > AxiMaxBeats_g then
491	                        v.RdMaxBeats := to_unsigned(AxiMaxBeats_g, BeatsBits_c);
492	                    else
493	                        v.RdMaxBeats := RdMax4kBeats_v(BeatsBits_c - 1 downto 0);
494	                    end if;
495	                    v.ReadTfGenState := GenTf_s;
496	
497	                when GenTf_s =>
498	                    if (r.RdMaxBeats < r.RdBeats) then
499	                        v.RdTfBeats  := r.RdMaxBeats;
500	                        v.RdTfIsLast := '0';
501	                    else
502	                        v.RdTfBeats  := r.RdBeats(BeatsBits_c - 1 downto 0);
503	                        v.RdTfIsLast := '1';
504	                    end if;
505	                    v.RdTfVld        := '1';
506	                    v.ReadTfGenState := WriteTf_s;
507	
508	                when WriteTf_s =>
509	                    if (r.RdTfVld = '1') and (r.ArFsmRdy = '1') then
510	                        v.RdTfVld := '0';
511	                        v.RdBeats := r.RdBeats - r.RdTfBeats;
512	                        v.RdAddr  := r.RdAddr + resize(2**UnusedAddrBits_c * r.RdTfBeats, v.RdAddr'length);
513	                        if r.RdTfIsLast = '1' then
514	                            v.ReadTfGenState := Idle_s;
515	                        else
516	                            v.ReadTfGenState := MaxCalc_s;
517	                        end if;
518	                    end if;
519	
520	                -- coverage off
521	                when others => null; -- unreachable code
522	                -- coverage on
523	
524	            end case;
525	
526	            -- Default Values
527	            v.ArCmdSent := '0';
528	
529	            -- AR Generation FSM
530	            case r.ArFsm is
531	                when Idle_s =>
532	                    if ((r.RdLowLat = '1') or (r.RdFifoSpaceFree >= signed('0' & r.RdTfBeats))) and
533	                       (r.RdOpenTrans < AxiMaxOpenTransactions_g) and (r.RdTfVld = '1') then
534	                        v.ArFsmRdy := '1';
535	                    end if;
536	                    if (r.ArFsmRdy = '1') and (r.RdTfVld = '1') then
537	                        v.ArFsmRdy      := '0';
538	                        v.M_Axi_ArAddr  := std_logic_vector(r.RdAddr);
539	                        Stdlv9Bit_v     := std_logic_vector(resize(r.RdTfBeats - 1, 9));
540	                        v.M_Axi_ArLen   := Stdlv9Bit_v(7 downto 0);
541	                        v.M_Axi_ArValid := '1';
542	                        v.ArFsm         := Wait_s;
543	                        v.ArCmdSent     := '1';
544	                        v.ArCmdSize     := r.RdTfBeats;
545	                        v.ArCmdSizeMin1 := r.RdTfBeats - 1;
546	                    end if;
547	
548	                when Wait_s =>
549	                    if M_Axi_ArReady = '1' then
550	                        v.RdOpenTrans   := r.RdOpenTrans + 1;
551	                        v.M_Axi_ArValid := '0';
552	                        v.ArFsm         := Idle_s;
553	                    end if;
554	
555	                -- coverage off
556	                when others => null; -- unreachable code
557	                -- coverage on
558	
559	            end case;
560	
561	            -- Update counter for FIFO entries that were not yet announced in a command
562	            -- .. Implementation is a bit weird for timing optimization reasons.
563	            -- Use registered RDataFifoRead: This helps with timing and it does not introduce any risk since
564	            -- .. the decrement is still done immediately, the increment is delayed by one clock cycle. So worst
565	            -- .. case a High-Latency transfer is delayed by one cycle which is acceptable.
566	            v.RDataFifoRead := Rd_Ready and RdDat_Vld_I;
567	            if r.ArCmdSent = '1' then
568	                if r.RDataFifoRead = '1' then
569	                    v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSizeMin1); -- Decrement by size and increment by one (timing opt)
570	                else
571	                    v.RdFifoSpaceFree := r.RdFifoSpaceFree - signed('0' & r.ArCmdSize);
572	                end if;
573	            elsif r.RDataFifoRead = '1' then
574	                v.RdFifoSpaceFree := r.RdFifoSpaceFree + 1;
575	            end if;
576	
577	            -- *** R Response Generation ***
578	            -- Default Values
579	            v.Rd_Done  := '0';
580	            v.Rd_Error := '0';
581	
582	            -- FSM
583	            if RdRespLast = '1' then
584	                v.RdOpenTrans := v.RdOpenTrans - 1; -- Use v. because it may have been modified above and this modification has not to be overriden
585	                if RdRespIsLast = '1' then
586	                    if (M_Axi_RResp /= AxiResp_Okay_c) then
587	                        v.Rd_Error := '1';
588	                    else
589	                        v.Rd_Error    := r.RdRespError;
590	                        v.Rd_Done     := not r.RdRespError;
591	                        v.RdRespError := '0';
592	                    end if;
593	                elsif M_Axi_RResp /= AxiResp_Okay_c then
594	                    v.RdRespError := '1';
595	                end if;
596	            end if;
597	
598	        end if;
599	
600	        -- *** Update Signal ***
601	        r_next <= v;
602	    end process;
603	
604	    -- *** Registered Process ***
605	    p_reg : process (Clk) is
606	    begin
607	        if rising_edge(Clk) then
608	            r <= r_next;
609	            if Rst = '1' then
610	                -- Write Related Registers
611	                if ImplWrite_g then
612	                    r.CmdWr_Ready     <= '0';
613	                    r.WriteTfGenState <= Idle_s;
614	                    r.WrTfVld         <= '0';
615	                    r.AwFsm           <= Idle_s;
616	                    r.AwFsmRdy        <= '0';
617	                    r.AwCmdSent       <= '0';
618	                    r.M_Axi_AwValid   <= '0';
619	                    r.WDataFifoRd     <= '0';
620	                    r.WDataEna        <= '0';
621	                    r.WrOpenTrans     <= 0;
622	                    r.WrRespError     <= '0';
623	                    r.Wr_Done         <= '0';
624	                    r.Wr_Error        <= '0';
625	                    r.WrBeatsNoCmd    <= (others => '0');
626	                    r.WFsm            <= Idle_s;
627	                    r.WDataFifoWrite  <= '0';
628	                end if;
629	                -- Read Related Registers
630	                if ImplRead_g then
631	                    r.CmdRd_Ready     <= '0';
632	                    r.ReadTfGenState  <= Idle_s;
633	                    r.RdTfVld         <= '0';
634	                    r.ArFsmRdy        <= '0';
635	                    r.ArCmdSent       <= '0';
636	                    r.M_Axi_ArValid   <= '0';
637	                    r.ArFsm           <= Idle_s;
638	                    r.RdOpenTrans     <= (others => '0');
639	                    r.RdRespError     <= '0';
640	                    r.Rd_Done         <= '0';
641	                    r.Rd_Error        <= '0';
642	                    r.RdFifoSpaceFree <= to_signed(DataFifoDepth_g, r.RdFifoSpaceFree'length);
643	                    r.RDataFifoRead   <= '0';
644	                end if;
645	            end if;
646	        end if;
647	    end process;
648	
649	    -- *** Outputs ***
650	    CmdWr_Ready   <= r.CmdWr_Ready;
651	    M_Axi_AwAddr  <= r.M_Axi_AwAddr;
652	    M_Axi_AwLen   <= r.M_Axi_AwLen;
653	    M_Axi_AwValid <= r.M_Axi_AwValid;
654	    M_Axi_WLast   <= r.M_Axi_WLast;
655	    Wr_Done       <= r.Wr_Done;
656	    Wr_Error      <= r.Wr_Error;
657	    CmdRd_Ready   <= r.CmdRd_Ready;
658	    M_Axi_ArAddr  <= r.M_Axi_ArAddr;
659	    M_Axi_ArLen   <= r.M_Axi_ArLen;
660	    M_Axi_ArValid <= r.M_Axi_ArValid;
661	    Rd_Done       <= r.Rd_Done;
662	    Rd_Error      <= r.Rd_Error;
663	
664	    -- *** Constant Outputs ***
665	    M_Axi_AwSize  <= std_logic_vector(to_unsigned(log2(AxiDataWidth_g / 8), 3));
666	    M_Axi_ArSize  <= std_logic_vector(to_unsigned(log2(AxiDataWidth_g / 8), 3));
667	    M_Axi_AwBurst <= AxiBurst_Incr_c;
668	    M_Axi_ArBurst <= AxiBurst_Incr_c;
669	    M_Axi_AwCache <= "0011";              -- According AXI reference guide
670	    M_Axi_ArCache <= "0011";              -- According AXI reference guide
671	    M_Axi_AwProt  <= "000";               -- According AXI reference guide
672	    M_Axi_ArProt  <= "000";               -- According AXI reference guide
673	    M_Axi_AwLock  <= '0';                 -- Exclusive access support not implemented
674	    M_Axi_ArLock  <= '0';                 -- Exclusive access support not implemented
675	    M_Axi_BReady  <= '1' when ImplWrite_g else '0';
676	
677	    -----------------------------------------------------------------------------------------------
678	    -- Instantiations
679	    -----------------------------------------------------------------------------------------------
680	
681	    -- *** Write FIFOs ***
682	    g_write : if ImplWrite_g generate
683	
684	        -- *** FIFO for data transfer FSM ***
685	        -- Generate Valid
686	        WrTransFifoInVld <= r.AwFsmRdy and r.WrTfVld;
687	
688	        -- Instance
689	        i_fifo_wr_trans : entity work.olo_base_fifo_sync
690	            generic map (
691	                Width_g        => BeatsBits_c,
692	                Depth_g        => AxiMaxOpenTransactions_g,
693	                RamBehavior_g  => RamBehavior_g
694	            )
695	            port map (
696	                Clk         => Clk,
697	                Rst         => Rst,
698	                In_Data     => std_logic_vector(r.WrTfBeats),
699	                In_Valid    => WrTransFifoInVld,
700	                In_Ready    => open,                  -- Not required since maximum of open transactions is limitted
701	                Out_Data    => WrTransFifoBeats,
702	                Out_Valid   => WrTransFifoOutVld,
703	                Out_Ready   => r.WDataFifoRd
704	            );
705	
706	        -- *** Write Data FIFO ***
707	        b_fifo_wr_data : block is
708	            signal InData  : std_logic_vector(Wr_Data'length + Wr_Be'length - 1 downto 0);
709	            signal OutData : std_logic_vector(InData'range);
710	        begin
711	            -- Assemble input
712	            InData(Wr_Data'high downto Wr_Data'low)                     <= Wr_Data;
713	            InData(Wr_Data'high + Wr_Be'length downto Wr_Data'high + 1) <= Wr_Be;
714	
715	            -- Instance
716	            i_fifo_wr_data : entity work.olo_base_fifo_sync
717	                generic map (
718	                    Width_g         => Wr_Data'length + Wr_Be'length,
719	                    Depth_g         => DataFifoDepth_g,
720	                    RamBehavior_g   => RamBehavior_g
721	                )
722	                port map (
723	                    Clk         => Clk,
724	                    Rst         => Rst,
725	                    In_Data     => InData,
726	                    In_Valid    => Wr_Valid,
727	                    In_Ready    => WrData_Rdy_I,
728	                    Out_Data    => OutData,
729	                    Out_Valid   => WrDataFifoOVld,
730	                    Out_Ready   => WrDataFifoORdy
731	                );
732	
733	            -- Disassemble output
734	            M_Axi_WData    <= OutData(Wr_Data'high downto Wr_Data'low);
735	            M_Axi_WStrb    <= OutData(Wr_Data'high + Wr_Be'length downto Wr_Data'high + 1);
736	            M_Axi_WValid   <= WrDataFifoOVld and r.WDataEna;
737	            WrDataFifoORdy <= M_Axi_WReady and r.WDataEna;
738	            Wr_Ready       <= WrData_Rdy_I;
739	        end block;
740	
741	        -- FIFO for write response FSM
742	        i_fifo_wr_resp : entity work.olo_base_fifo_sync
743	            generic map (
744	                Width_g        => 1,
745	                Depth_g        => AxiMaxOpenTransactions_g,
746	                RamBehavior_g  => RamBehavior_g
747	            )
748	            port map (
749	                Clk         => Clk,
750	                Rst         => Rst,
751	                In_Data(0)  => r.WrTfIsLast,
752	                In_Valid    => WrTransFifoInVld,
753	                In_Ready    => open,               -- Not required since maximum of open transactions is limitted
754	                Out_Data(0) => WrRespIsLast,
755	                Out_Valid   => WrRespFifoVld,
756	                Out_Ready   => M_Axi_BValid
757	            );
758	
759	    end generate;
760	
761	    -- Tie signals to ground if read not implemented
762	    g_nwrite : if not ImplWrite_g generate
763	        M_Axi_WStrb  <= (others => '0');
764	        M_Axi_WData  <= (others => '0');
765	        M_Axi_WValid <= '0';
766	        Wr_Ready     <= '0';
767	    end generate;
768	
769	    -- *** Read FIFOs ***
770	    g_read : if ImplRead_g generate
771	
772	        -- Read Data FIFO
773	        b_fifo_rd_data : block is
774	            signal InData, OutData : std_logic_vector(Rd_Data'length downto 0);
775	        begin
776	            -- Assemble Input data
777	            InData(M_Axi_RData'high downto 0) <= M_Axi_RData;
778	            -- Only forward last flag for the last burst of a user transfer (RdRespIsLast)
779	            InData(M_Axi_RData'high + 1) <= M_Axi_RLast and RdRespIsLast;
780	
781	            -- FIFO
782	            i_fifo_rd_data : entity work.olo_base_fifo_sync
783	                generic map (
784	                    Width_g        => Rd_Data'length+1,
785	                    Depth_g        => DataFifoDepth_g,
786	                    RamBehavior_g  => RamBehavior_g
787	                )
788	                port map (
789	                    Clk         => Clk,
790	                    Rst         => Rst,
791	                    In_Data     => InData,
792	                    In_Valid    => M_Axi_RValid,
793	                    In_Ready    => M_Axi_RReady_I,
794	                    Out_Data    => OutData,
795	                    Out_Valid   => RdDat_Vld_I,
796	                    Out_Ready   => Rd_Ready
797	                );
798	
799	            -- Disassemble Output data
800	            Rd_Data      <= OutData(Rd_Data'high downto 0);
801	            Rd_Last      <= OutData(Rd_Data'high+1);
802	            Rd_Valid     <= RdDat_Vld_I;
803	            M_Axi_RReady <= M_Axi_RReady_I;
804	        end block;
805	
806	        -- Assemble FIFO input
807	        RdTransFifoInVld <= r.ArFsmRdy and r.RdTfVld;
808	        RdRespLast       <= M_Axi_RValid and M_Axi_RReady_I and M_Axi_RLast;
809	
810	        -- FIFO instance
811	        i_fifo_rd_resp : entity work.olo_base_fifo_sync
812	            generic map (
813	                Width_g        => 1,
814	                Depth_g        => AxiMaxOpenTransactions_g,
815	                RamBehavior_g  => RamBehavior_g
816	            )
817	            port map (
818	                Clk         => Clk,
819	                Rst         => Rst,
820	                In_Data(0)  => r.RdTfIsLast,
821	                In_Valid    => RdTransFifoInVld,
822	                In_Ready    => open,               -- Not required since maximum of open transactions is limitted
823	                Out_Data(0) => RdRespIsLast,
824	                Out_Valid   => RdRespFifoVld,
825	                Out_Ready   => RdRespLast
826	            );
827	
828	    end generate;
829	
830	    -- Tie signals to ground if read not implemented
831	    g_nread : if not ImplRead_g generate
832	        M_Axi_RReady <= '0';
833	        Rd_Data      <= (others => '0');
834	        Rd_Valid     <= '0';
835	    end generate;
836	
837	end architecture;
838

