26	    use work.olo_test_axi_slave_pkg.all;
27	
28	---------------------------------------------------------------------------------------------------
29	-- Entity
30	---------------------------------------------------------------------------------------------------
31	-- vunit: run_all_in_same_sim
32	entity olo_axi_master_simple_tb is
33	    generic (
34	        AxiAddrWidth_g              : natural range 12 to 64 := 32;
35	        AxiDataWidth_g              : natural range 8 to 64  := 32;
36	        AxiMaxOpenTransactions_g    : natural range 1 to 8   := 2;
37	        ImplRead_g                  : boolean                := true;
38	        ImplWrite_g                 : boolean                := true;
39	        RamBehavior_g               : string                 := "RBW";
40	        runner_cfg                  : string
41	    );
42	end entity;
43	
44	architecture sim of olo_axi_master_simple_tb is
45	
46	    -----------------------------------------------------------------------------------------------
47	    -- Fixed Generics
48	    -----------------------------------------------------------------------------------------------
49	    constant UserTransactionSizeBits_c : natural := 10;
50	    constant AxiMaxBeats_c             : natural := 32;
51	    constant DataFifoDepth_c           : natural := 16;
52	
53	    -----------------------------------------------------------------------------------------------
54	    -- AXI Definition
55	    -----------------------------------------------------------------------------------------------
56	    constant ByteWidth_c : integer := AxiDataWidth_g/8;
57	
58	    subtype IdRange_c   is natural range -1 downto 0;
59	    subtype AddrRange_c is natural range AxiAddrWidth_g-1 downto 0;
60	    subtype UserRange_c is natural range 1 downto 0;
61	    subtype DataRange_c is natural range AxiDataWidth_g-1 downto 0;
62	    subtype ByteRange_c is natural range ByteWidth_c-1 downto 0;
63	
64	    signal AxiMs : axi_ms_t (ar_id(IdRange_c), aw_id(IdRange_c),
65	                              ar_addr(AddrRange_c), aw_addr(AddrRange_c),
66	                              ar_user(UserRange_c), aw_user(UserRange_c), w_user(UserRange_c),
67	                              w_data(DataRange_c),
68	                              w_strb(ByteRange_c));
69	
70	    signal AxiSm : axi_sm_t (r_id(IdRange_c), b_id(IdRange_c),
71	                              r_user(UserRange_c), b_user(UserRange_c),
72	                              r_data(DataRange_c));
73	
74	    -----------------------------------------------------------------------------------------------
75	    -- Constants
76	    -----------------------------------------------------------------------------------------------
77	    subtype CmdAddrRange_c is natural range AxiAddrWidth_g-1 downto 0;
78	    subtype CmdSizeRange_c is natural range UserTransactionSizeBits_c+CmdAddrRange_c'high downto CmdAddrRange_c'high+1;
79	    constant CmdLowLat_c : natural := CmdSizeRange_c'high+1;
80	
81	    subtype DatDataRange_c is natural range AxiDataWidth_g-1 downto 0;
82	    subtype DatBeRange_c is natural range AxiDataWidth_g/8+DatDataRange_c'high downto DatDataRange_c'high+1;
83	
84	    -----------------------------------------------------------------------------------------------
85	    -- TB Defnitions
86	    -----------------------------------------------------------------------------------------------
87	    constant Clk_Frequency_c : real := 100.0e6;
88	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
89	
90	    type Response_t is (RespSuccess, RespError);
91	
92	    -----------------------------------------------------------------------------------------------
93	    -- Interface Signals
94	    -----------------------------------------------------------------------------------------------
95	    signal Clk          : std_logic                                                := '0';
96	    signal Rst          : std_logic                                                := '0';
97	    signal CmdWr_Addr   : std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
98	    signal CmdWr_Size   : std_logic_vector(UserTransactionSizeBits_c - 1 downto 0) := (others => '0');
99	    signal CmdWr_LowLat : std_logic                                                := '0';
100	    signal CmdWr_Valid  : std_logic                                                := '0';
101	    signal CmdWr_Ready  : std_logic;
102	    signal CmdRd_Addr   : std_logic_vector(AxiAddrWidth_g - 1 downto 0)            := (others => '0');
103	    signal CmdRd_Size   : std_logic_vector(UserTransactionSizeBits_c - 1 downto 0) := (others => '0');
104	    signal CmdRd_LowLat : std_logic                                                := '0';
105	    signal CmdRd_Valid  : std_logic                                                := '0';
106	    signal CmdRd_Ready  : std_logic;
107	    signal Wr_Data      : std_logic_vector(AxiDataWidth_g - 1 downto 0)            := (others => '0');
108	    signal Wr_Be        : std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0)        := (others => '0');
109	    signal Wr_Valid     : std_logic                                                := '0';
110	    signal Wr_Ready     : std_logic;
111	    signal Rd_Data      : std_logic_vector(AxiDataWidth_g - 1 downto 0);
112	    signal Rd_Valid     : std_logic;
113	    signal Rd_Ready     : std_logic                                                := '0';
114	    signal Wr_Done      : std_logic;
115	    signal Wr_Error     : std_logic;
116	    signal Rd_Done      : std_logic;
117	    signal Rd_Error     : std_logic;
118	    signal Rd_Last      : std_logic;
119	
120	    -----------------------------------------------------------------------------------------------
121	    -- TB Defnitions
122	    -----------------------------------------------------------------------------------------------
123	
124	    -- *** Verification Compnents ***
125	    constant AxiSlave_c     : olo_test_axi_slave_t := new_olo_test_axi_slave (
126	        data_width => AxiDataWidth_g,
127	        addr_width => AxiAddrWidth_g,
128	        id_width => 0
129	    );
130	    constant RdDataSlave_c  : axi_stream_slave_t   := new_axi_stream_slave (
131	        data_length => AxiDataWidth_g,
132	        stall_config => new_stall_config(0.0, 0, 0)
133	    );
134	    constant WrCmdMaster_c  : axi_stream_master_t  := new_axi_stream_master (
135	        data_length => AxiAddrWidth_g+UserTransactionSizeBits_c+1,
136	        stall_config => new_stall_config(0.0, 0, 0)
137	    );
138	    constant RdCmdMaster_c  : axi_stream_master_t  := new_axi_stream_master (
139	        data_length => AxiAddrWidth_g+UserTransactionSizeBits_c+1,
140	        stall_config => new_stall_config(0.0, 0, 0)
141	    );
142	    constant WrDataMaster_c : axi_stream_master_t  := new_axi_stream_master (
143	        data_length => AxiDataWidth_g+AxiDataWidth_g/8,
144	        stall_config => new_stall_config(0.0, 0, 0)
145	    );
146	
147	    procedure pushCommand (
148	        signal net : inout network_t;
149	        CmdMaster  : axi_stream_master_t;
150	        CmdAddr    : unsigned;
151	        CmdSize    : integer;
152	        CmdLowLat  : std_logic := '0') is
153	        variable TData_v : std_logic_vector(CmdLowLat_c downto 0);
154	    begin
155	        TData_v(CmdAddrRange_c) := std_logic_vector(resize(CmdAddr, AxiAddrWidth_g));
156	        TData_v(CmdSizeRange_c) := toUslv(CmdSize, UserTransactionSizeBits_c);
157	        TData_v(CmdLowLat_c)    := CmdLowLat;
158	        push_axi_stream(net, CmdMaster, TData_v);
159	    end procedure;
160	
161	    procedure pushWrData (
162	        signal net : inout network_t;
163	        startValue : unsigned;
164	        increment  : natural          := 1;
165	        beats      : natural          := 1;
166	        firstStrb  : std_logic_vector := onesVector(AxiDataWidth_g/8);
167	        lastStrb   : std_logic_vector := onesVector(AxiDataWidth_g/8)) is
168	        variable TData_v : std_logic_vector(DatBeRange_c'high downto 0);
169	        variable Data_v  : unsigned(AxiDataWidth_g-1 downto 0);
170	    begin
171	        Data_v := resize(startValue, AxiDataWidth_g);
172	
173	        -- loop through beats
174	        for i in 0 to beats-1 loop
175	            TData_v(DatDataRange_c) := std_logic_vector(Data_v);
176	            if i = 0 then
177	                TData_v(DatBeRange_c) := firstStrb;
178	            elsif i = beats-1 then
179	                TData_v(DatBeRange_c) := lastStrb;
180	            else
181	                TData_v(DatBeRange_c) := (others => '1');
182	            end if;
183	            push_axi_stream(net, WrDataMaster_c, TData_v);
184	            Data_v := Data_v + increment;
185	        end loop;
186	
187	    end procedure;
188	
189	    procedure expectRdData (
190	        signal net : inout network_t;
191	        startValue : unsigned;
192	        increment  : natural := 1;
193	        beats      : natural := 1) is
194	        variable Data_v : unsigned(AxiDataWidth_g-1 downto 0);
195	        variable Last_v : std_logic := '0';
196	    begin
197	        Data_v := resize(startValue, AxiDataWidth_g);
198	
199	        -- loop through beats
200	        for i in 0 to beats-1 loop
201	            -- Last is set on the last beat
202	            if i = beats-1 then
203	                Last_v := '1';
204	            end if;
205	            check_axi_stream(net, RdDataSlave_c, std_logic_vector(Data_v), blocking => false, tlast => Last_v, msg => "RdData " & integer'image(i));
206	            Data_v := Data_v + increment;
207	        end loop;
208	
209	    end procedure;
210	
211	    procedure expectWrResponse (Response : Response_t) is
212	    begin
213	        wait until rising_edge(Clk) and ((Wr_Done = '1') or (Wr_Error = '1'));
214	        if Response = RespSuccess then
215	            check_equal(Wr_Error, '0', "Wrong Wr_Error");
216	            check_equal(Wr_Done, '1', "Wrong Wr_Done");
217	        else
218	            check_equal(Wr_Error, '1', "Wrong Wr_Error");
219	            check_equal(Wr_Done, '0', "Wrong Wr_Done");
220	        end if;
221	    end procedure;
222	
223	    procedure expectRdResponse (Response : Response_t) is
224	    begin
225	        wait until rising_edge(Clk) and ((Rd_Done = '1') or (Rd_Error = '1'));
226	        if Response = RespSuccess then
227	            check_equal(Rd_Error, '0', "Wrong Rd_Error");
228	            check_equal(Rd_Done, '1', "Wrong Rd_Done");
229	        else
230	            check_equal(Rd_Error, '1', "Wrong Rd_Error");
231	            check_equal(Rd_Done, '0', "Wrong Rd_Done");
232	        end if;
233	    end procedure;
234	
235	begin
236	
237	    -----------------------------------------------------------------------------------------------
238	    -- TB Control
239	    -----------------------------------------------------------------------------------------------
240	    test_runner_watchdog(runner, 1 ms);
241	
242	    p_control : process is
243	    begin
244	        test_runner_setup(runner, runner_cfg);
245	
246	        while test_suite loop
247	
248	            -- Reset
249	            wait until rising_edge(Clk);
250	            Rst <= '1';
251	            wait for 1 us;
252	            wait until rising_edge(Clk);
253	            Rst <= '0';
254	            wait until rising_edge(Clk);
255	
256	            if run("ResetValues") then
257	                if ImplRead_g then
258	                    check_equal(Rd_Valid, '0', "Rd_Valid");
259	                    check_equal(Rd_Done, '0', "Rd_Done");
260	                    check_equal(Rd_Error, '0', "Rd_Error");
261	                end if;
262	                if ImplWrite_g then
263	                    check_equal(Wr_Done, '0', "Wr_Done");
264	                    check_equal(Wr_Error, '0', "Wr_Error");
265	                end if;
266	
267	            end if;
268	
269	            -- *** Single Writes ***
270	            if run("SingleWrite-DataCmdTogether") then
271	                -- Only applies if Write is implemented
272	                if ImplWrite_g then
273	
274	                    -- Both latency modes
275	                    for LowLatency in 0 to 1 loop
276	                        -- Slave
277	                        expect_single_write (net, AxiSlave_c, X"1080", X"ABCD");
278	                        -- Master
279	                        pushCommand(net, WrCmdMaster_c, X"1080", 1, CmdLowLat => choose(LowLatency=1, '1', '0'));
280	                        pushWrData(net, X"ABCD");
281	                        -- Blocking
282	                        expectWrResponse(RespSuccess);
283	                    end loop;
284	
285	                end if;
286	            end if;
287	
288	            if run("SingleWrite-DataBeforeCmd") then
289	                -- Only applies if Write is implemented
290	                if ImplWrite_g then
291	
292	                    -- Both latency modes
293	                    for LowLatency in 0 to 1 loop
294	                        -- Slave
295	                        expect_single_write (net, AxiSlave_c, X"1088", X"ABC1");
296	                        -- Master
297	                        pushWrData(net, X"ABC1");
298	                        wait for 200 ns;
299	                        pushCommand(net, WrCmdMaster_c, X"1088", 1, CmdLowLat => choose(LowLatency=1, '1', '0'));
300	                        -- Blocking
301	                        expectWrResponse(RespSuccess);
302	                    end loop;
303	
304	                end if;
305	            end if;
306	
307	            if run("SingleWrite-CmdBeforeData") then
308	                if ImplWrite_g then
309	
310	                    -- Both latency modes
311	                    for LowLatency in 0 to 1 loop
312	                        -- Master
313	                        pushCommand(net, WrCmdMaster_c, X"1090", 1, CmdLowLat => choose(LowLatency=1, '1', '0'));
314	                        wait for 200 ns;
315	                        if LowLatency = 0 then
316	                            check_equal(AxiMs.aw_valid, '0', "HighLatency write executed before data was present");
317	                        else
318	                            check_equal(AxiMs.aw_valid, '1', "LowLatency write not executed before data was present");
319	                        end if;
320	                        pushWrData(net, X"ABC2");
321	                        -- Slave
322	                        expect_single_write (net, AxiSlave_c, X"1090", X"ABC2");
323	                        -- Blocking
324	                        expectWrResponse(RespSuccess);
325	                    end loop;
326	
327	                end if;
328	            end if;
329	
330	            if run("SingleWrite-DelayedAwReady") then
331	                if ImplWrite_g then
332	                    -- Slave
333	                    expect_single_write (net, AxiSlave_c, X"0100", X"03", aw_ready_delay => 200 ns);
334	                    -- Master
335	                    pushCommand(net, WrCmdMaster_c, X"0100", 1);
336	                    pushWrData(net, X"03");
337	                    -- Blocking
338	                    expectWrResponse(RespSuccess);
339	                end if;
340	            end if;
341	
342	            if run("SingleWrite-DelayedWReady") then
343	                if ImplWrite_g then
344	                    -- Slave
345	                    expect_single_write (net, AxiSlave_c, X"0200", X"04", w_ready_delay => 200 ns);
346	                    -- Master
347	                    pushCommand(net, WrCmdMaster_c, X"0200", 1);
348	                    pushWrData(net, X"04");
349	                    -- Blocking
350	                    expectWrResponse(RespSuccess);
351	                end if;
352	            end if;
353	
354	            if run("SingleWrite-DelayedBValid") then
355	                if ImplWrite_g then
356	                    -- Slave
357	                    expect_single_write (net, AxiSlave_c, X"0208", X"05", b_valid_delay => 200 ns);
358	                    -- Master
359	                    pushCommand(net, WrCmdMaster_c, X"0208", 1);
360	                    pushWrData(net, X"05");
361	                    -- Blocking
362	                    expectWrResponse(RespSuccess);
363	                end if;
364	            end if;
365	
366	            if run("SingleWrite-RespError") then
367	                if ImplWrite_g then
368	                    -- Slave
369	                    expect_aw(net, AxiSlave_c, X"0300");
370	                    expect_w(net, AxiSlave_c, X"05");
371	                    push_b(net, AxiSlave_c, resp => AxiResp_SlvErr_c);
372	                    -- Master
373	                    pushCommand(net, WrCmdMaster_c, X"0300", 1);
374	                    pushWrData(net, X"05");
375	                    -- Blocking
376	                    expectWrResponse(RespError);
377	                end if;
378	            end if;
379	
380	            -- *** Single Reads ***
381	            if run("SingleRead") then
382	                if ImplRead_g then
383	
384	                    -- both latency modes
385	                    for LowLatency in 0 to 1 loop
386	                        -- Slave
387	                        push_single_read (net, AxiSlave_c, X"0200", X"120A");
388	                        -- Master
389	                        pushCommand(net, RdCmdMaster_c, X"0200", 1, CmdLowLat => choose(LowLatency=1, '1', '0'));
390	                        expectRdData(net, X"120A");
391	                        -- Blocking
392	                        expectRdResponse(RespSuccess);
393	                    end loop;
394	
395	                end if;
396	            end if;
397	
398	            if run("SingleRead-DelayedArReady") then
399	                if ImplRead_g then
400	                    -- Slave
401	                    push_single_read (net, AxiSlave_c, X"0208", X"10", ar_ready_delay => 200 ns);
402	                    -- Master
403	                    pushCommand(net, RdCmdMaster_c, X"0208", 1);
404	                    expectRdData(net, X"10");
405	                    -- Blocking
406	                    expectRdResponse(RespSuccess);
407	                end if;
408	            end if;
409	
410	            if run("SingleRead-DelayedRValid") then
411	                if ImplRead_g then
412	                    -- Slave
413	                    push_single_read (net, AxiSlave_c, X"0210", X"20", r_valid_delay => 200 ns);
414	                    -- Master
415	                    pushCommand(net, RdCmdMaster_c, X"0210", 1);
416	                    expectRdData(net, X"20");
417	                    -- Blocking
418	                    expectRdResponse(RespSuccess);
419	                end if;
420	            end if;
421	
422	            if run("SingleRead-RespError") then
423	                if ImplRead_g then
424	                    -- Slave
425	                    expect_ar(net, AxiSlave_c, X"0300");
426	                    push_r(net, AxiSlave_c, X"23", resp => AxiResp_SlvErr_c);
427	                    -- Master
428	                    pushCommand(net, RdCmdMaster_c, X"0300", 1);
429	                    expectRdData(net, X"23");
430	                    -- Blocking
431	                    expectRdResponse(RespError);
432	                end if;
433	            end if;
434	
435	            -- *** Burst Writes ***
436	            if run("BurstWrite") then
437	                if ImplWrite_g then
438	
439	                    -- Both latency modes
440	                    for LowLatency in 0 to 1 loop
441	                        -- Slave
442	                        expect_burst_write_aligned(net, AxiSlave_c, X"0100", X"1234", 1, 12);
443	                        -- Master
444	                        pushCommand(net, WrCmdMaster_c, X"0100", 12, CmdLowLat => choose(LowLatency=1, '1', '0'));
445	                        pushWrData(net, X"1234", 1, 12);
446	                        -- Blocking
447	                        expectWrResponse(RespSuccess);
448	                    end loop;
449	
450	                end if;
451	            end if;
452	
453	            if run("BurstWriteOver4kBoundary") then
454	                if ImplWrite_g then
455	                    -- 2 words before boundary, 6 after, 8 total
456	                    -- Slave
457	                    expect_burst_write_aligned(net, AxiSlave_c, X"1000"-2*AxiDataWidth_g/8, X"1234", 1, 2);
458	                    expect_burst_write_aligned(net, AxiSlave_c, X"1000", X"1236", 1, 6);
459	                    -- Master
460	                    pushCommand(net, WrCmdMaster_c, X"1000"-2*AxiDataWidth_g/8, 8);
461	                    pushWrData(net, X"1234", 1, 8);
462	                    -- Blocking
463	                    expectWrResponse(RespSuccess);
464	                end if;
465	            end if;
466	
467	            if run("BurstWrite-FirstBurstError") then
468	                if ImplWrite_g then
469	                    -- 2 words before boundary, 6 after, 8 total
470	                    -- Slave first burst
471	                    expect_aw(net, AxiSlave_c, X"2000"-2*AxiDataWidth_g/8, len => 2);
472	                    expect_w(net, AxiSlave_c, X"12", beats => 2);
473	                    push_b(net, AxiSlave_c, resp => AxiResp_SlvErr_c);
474	                    -- Slave second burst
475	                    expect_burst_write_aligned(net, AxiSlave_c, X"2000", X"14", 1, 6);
476	                    -- Master
477	                    pushCommand(net, WrCmdMaster_c, X"2000"-2*AxiDataWidth_g/8, 8);
478	                    pushWrData(net, X"12", 1, 8);
479	                    -- Blocking
480	                    expectWrResponse(RespError);
481	                end if;
482	            end if;
483	
484	            -- *** Burst Reads ***
485	            if run("BurstRead") then
486	                if ImplRead_g then
487	
488	                    -- Both latency modes
489	                    for LowLatency in 0 to 1 loop
490	                        -- Slave
491	                        push_burst_read_aligned (net, AxiSlave_c, X"0210", X"10EF", 1, 12);
492	                        -- Master
493	                        pushCommand(net, RdCmdMaster_c, X"0210", 12, CmdLowLat => choose(LowLatency=1, '1', '0'));
494	                        expectRdData(net, X"10EF", 1, 12);
495	                        -- Blocking
496	                        expectRdResponse(RespSuccess);
497	                    end loop;
498	
499	                end if;
500	            end if;
501	
502	            if run("BurstReadOver4kBoundary") then
503	                if ImplRead_g then
504	                    -- 2 words before boundary, 6 after, 8 total
505	                    -- Slave
506	                    push_burst_read_aligned (net, AxiSlave_c, X"2000"-2*AxiDataWidth_g/8, X"09", 1, 2);
507	                    push_burst_read_aligned (net, AxiSlave_c, X"2000", X"0B", 1, 6);
508	                    -- Master
509	                    pushCommand(net, RdCmdMaster_c, X"2000"-2*AxiDataWidth_g/8, 8);
510	                    expectRdData(net, X"09", 1, 8);
511	                    -- Blocking
512	                    expectRdResponse(RespSuccess);
513	                end if;
514	            end if;
515	
516	            if run("BurstRead-FirstBurstError") then
517	                if ImplRead_g then
518	                    -- 2 words before boundary, 6 after, 8 total
519	                    -- Slave first burst
520	                    expect_ar(net, AxiSlave_c, X"3000"-2*AxiDataWidth_g/8, len => 2);
521	                    push_r(net, AxiSlave_c, X"12", beats => 2, resp => AxiResp_SlvErr_c);
522	                    -- Slave second burst
523	                    push_burst_read_aligned (net, AxiSlave_c, X"3000", X"14", 1, 6);
524	                    -- Master
525	                    pushCommand(net, RdCmdMaster_c, X"3000"-2*AxiDataWidth_g/8, 8);
526	                    expectRdData(net, X"12", 1, 8);
527	                    -- Blocking
528	                    expectRdResponse(RespError);
529	                end if;
530	            end if;
531	
532	            -- *** Check if high-latency read command with full FIFO is delayed ***
533	            if run("BurstRead-FifoFull") then
534	                if ImplRead_g then
535	
536	                    -- both latency modes
537	                    for LowLatency in 0 to 1 loop
538	                        -- Fill FIFO
539	                        pushCommand(net, RdCmdMaster_c, X"4000", DataFifoDepth_c, CmdLowLat => choose(LowLatency=1, '1', '0'));
540	                        wait for 100 ns;
541	                        check_equal(AxiMs.ar_valid, '1', "Fill Command not Valid");
542	                        push_burst_read_aligned (net, AxiSlave_c, X"4000", X"10", 1, DataFifoDepth_c);
543	                        wait for 200 ns;
544	                        -- Push Second Command with full FIFO
545	                        pushCommand(net, RdCmdMaster_c, X"5000", 4, CmdLowLat => choose(LowLatency=1, '1', '0'));
546	                        wait for 200 ns;
547	                        if LowLatency = 0 then
548	                            check_equal(AxiMs.ar_valid, '0', "Second Command Valid despite full FIFO");
549	                        else
550	                            check_equal(AxiMs.ar_valid, '1', "Second Command not Valid despite low-latency");
551	                        end if;
552	                        -- Execute both commands
553	                        expectRdData(net, X"10", 1, DataFifoDepth_c);
554	                        push_burst_read_aligned (net, AxiSlave_c, X"5000", X"40", 1, 4);
555	                        expectRdData(net, X"40", 1, 4);
556	                        wait_until_idle(net, as_sync(RdDataSlave_c));
557	                    end loop;
558	
559	                end if;
560	            end if;
561	
562	            -- *** Test handshake on Data Lane ***
563	            if run("BurstRead-SlowData") then
564	                if ImplRead_g then
565	                    -- Slave
566	                    push_burst_read_aligned (net, AxiSlave_c, X"0210", X"10EF", 1, 12, beat_delay => 50 ns);
567	                    -- Master
568	                    pushCommand(net, RdCmdMaster_c, X"0210", 12, CmdLowLat => '0');
569	                    expectRdData(net, X"10EF", 1, 12);
570	                    -- Blocking
571	                    expectRdResponse(RespSuccess);
572	                end if;
573	            end if;
574	
575	            if run("BurstWrite-SlowData") then
576	                if ImplWrite_g then
577	                    -- Slave
578	                    expect_burst_write_aligned(net, AxiSlave_c, X"0100", X"1234", 1, 12, beat_delay => 50 ns);
579	                    -- Master
580	                    pushCommand(net, WrCmdMaster_c, X"0100", 12, CmdLowLat => '0');
581	                    pushWrData(net, X"1234", 1, 12);
582	                    -- Blocking
583	                    expectWrResponse(RespSuccess);
584	                end if;
585	            end if;
586	
587	            -- *** Split Transfers at Maximum Transaction Size ***
588	            if run("BurstRead-MaxTransactionSize") then
589	                if ImplRead_g then
590	                    -- Slave
591	                    push_burst_read_aligned (net, AxiSlave_c, X"0210", X"10EF", 1, AxiMaxBeats_c);
592	                    push_burst_read_aligned (net, AxiSlave_c, X"0210"+AxiMaxBeats_c*ByteWidth_c, X"10EF"+AxiMaxBeats_c, 1, AxiMaxBeats_c);
593	                    push_burst_read_aligned (net, AxiSlave_c, X"0210"+AxiMaxBeats_c*2*ByteWidth_c, X"10EF"+AxiMaxBeats_c*2, 1, 5);
594	                    -- Master
595	                    pushCommand(net, RdCmdMaster_c, X"0210", AxiMaxBeats_c*2+5, CmdLowLat => '1'); -- must be lowlatency becuause larger than FIFO
596	                    expectRdData(net, X"10EF", 1, AxiMaxBeats_c*2+5);
597	                    -- Blocking
598	                    expectRdResponse(RespSuccess);
599	                end if;
600	            end if;
601	
602	            if run("BurstWrite-MaxTransactionSize") then
603	                if ImplWrite_g then
604	                    -- Slave
605	                    expect_burst_write_aligned(net, AxiSlave_c, X"0100", X"1234", 1, AxiMaxBeats_c);
606	                    expect_burst_write_aligned(net, AxiSlave_c, X"0100"+AxiMaxBeats_c*ByteWidth_c, X"1234"+AxiMaxBeats_c, 1, AxiMaxBeats_c);
607	                    expect_burst_write_aligned(net, AxiSlave_c, X"0100"+AxiMaxBeats_c*2*ByteWidth_c, X"1234"+AxiMaxBeats_c*2, 1, 5);
608	                    -- Master
609	                    pushCommand(net, WrCmdMaster_c, X"0100", AxiMaxBeats_c*2+5, CmdLowLat => '1'); -- must be lowlatency becuause larger than FIFO
610	                    pushWrData(net, X"1234", 1, AxiMaxBeats_c*2+5);
611	                    -- Blocking
612	                    expectWrResponse(RespSuccess);
613	                end if;
614	            end if;
615	
616	            -- Wait for idle
617	            wait_until_idle(net, as_sync(AxiSlave_c));
618	            wait_until_idle(net, as_sync(RdDataSlave_c));
619	            wait_until_idle(net, as_sync(WrCmdMaster_c));
620	            wait_until_idle(net, as_sync(RdCmdMaster_c));
621	            wait_until_idle(net, as_sync(WrDataMaster_c));
622	            wait for 1 us;
623	
624	        end loop;
625	
626	        -- TB done
627	        test_runner_cleanup(runner);
628	    end process;
629	
630	    -----------------------------------------------------------------------------------------------
631	    -- Clock
632	    -----------------------------------------------------------------------------------------------
633	    Clk <= not Clk after 0.5*Clk_Period_c;
634	
635	    -----------------------------------------------------------------------------------------------
636	    -- DUT
637	    -----------------------------------------------------------------------------------------------
638	    i_dut : entity olo.olo_axi_master_simple
639	        generic map (
640	            AxiAddrWidth_g              => AxiAddrWidth_g,
641	            AxiDataWidth_g              => AxiDataWidth_g,
642	            AxiMaxBeats_g               => AxiMaxBeats_c,
643	            AxiMaxOpenTransactions_g    => AxiMaxOpenTransactions_g,
644	            -- User Configuration
645	            UserTransactionSizeBits_g   => UserTransactionSizeBits_c,
646	            DataFifoDepth_g             => DataFifoDepth_c,
647	            ImplRead_g                  => ImplRead_g,
648	            ImplWrite_g                 => ImplWrite_g,
649	            RamBehavior_g               => RamBehavior_g
650	        )
651	        port map (
652	            -- Control Signals
653	            Clk            => Clk,
654	            Rst            => Rst,
655	            -- User Command Interface
656	            CmdWr_Addr     => CmdWr_Addr,
657	            CmdWr_Size     => CmdWr_Size,
658	            CmdWr_LowLat   => CmdWr_LowLat,
659	            CmdWr_Valid    => CmdWr_Valid,
660	            CmdWr_Ready    => CmdWr_Ready,
661	            -- User Command Interface
662	            CmdRd_Addr     => CmdRd_Addr,
663	            CmdRd_Size     => CmdRd_Size,
664	            CmdRd_LowLat   => CmdRd_LowLat,
665	            CmdRd_Valid    => CmdRd_Valid,
666	            CmdRd_Ready    => CmdRd_Ready,
667	            -- Write Data
668	            Wr_Data        => Wr_Data,
669	            Wr_Be          => Wr_Be,
670	            Wr_Valid       => Wr_Valid,
671	            Wr_Ready       => Wr_Ready,
672	            -- Read Data
673	            Rd_Data        => Rd_Data,
674	            Rd_Valid       => Rd_Valid,
675	            Rd_Ready       => Rd_Ready,
676	            Rd_Last        => Rd_Last,
677	            -- Response
678	            Wr_Done        => Wr_Done,
679	            Wr_Error       => Wr_Error,
680	            Rd_Done        => Rd_Done,
681	            Rd_Error       => Rd_Error,
682	            -- AXI Address Write Channel
683	            M_Axi_AwAddr   => AxiMs.aw_addr,
684	            M_Axi_AwValid  => AxiMs.aw_valid,
685	            M_Axi_AwReady  => AxiSm.aw_ready,
686	            M_Axi_AwLen    => AxiMs.aw_len,
687	            M_Axi_AwSize   => AxiMs.aw_size,
688	            M_Axi_AwBurst  => AxiMs.aw_burst,
689	            M_Axi_AwLock   => AxiMs.aw_lock,
690	            M_Axi_AwCache  => AxiMs.aw_cache,
691	            M_Axi_AwProt   => AxiMs.aw_prot,
692	            -- AXI Write Data Channel
693	            M_Axi_WData    => AxiMs.w_data,
694	            M_Axi_WStrb    => AxiMs.w_strb,
695	            M_Axi_WValid   => AxiMs.w_valid,
696	            M_Axi_WReady   => AxiSm.w_ready,
697	            M_Axi_WLast    => AxiMs.w_last,
698	            -- AXI Write Response Channel
699	            M_Axi_BResp    => AxiSm.b_resp,
700	            M_Axi_BValid   => AxiSm.b_valid,
701	            M_Axi_BReady   => AxiMs.b_ready,
702	            -- AXI Read Address Channel
703	            M_Axi_ArAddr   => AxiMs.ar_addr,
704	            M_Axi_ArValid  => AxiMs.ar_valid,
705	            M_Axi_ArReady  => AxiSm.ar_ready,
706	            M_Axi_ArLen    => AxiMs.ar_len,
707	            M_Axi_ArSize   => AxiMs.ar_size,
708	            M_Axi_ArBurst  => AxiMs.ar_burst,
709	            M_Axi_ArLock   => AxiMs.ar_lock,
710	            M_Axi_ArCache  => AxiMs.ar_cache,
711	            M_Axi_ArProt   => AxiMs.ar_prot,
712	            -- AXI Read Data Channel
713	            M_Axi_RData    => AxiSm.r_data,
714	            M_Axi_RValid   => AxiSm.r_valid,
715	            M_Axi_RReady   => AxiMs.r_ready,
716	            M_Axi_RResp    => AxiSm.r_resp,
717	            M_Axi_RLast    => AxiSm.r_last
718	        );
719	
720	    -----------------------------------------------------------------------------------------------
721	    -- Verification Components
722	    -----------------------------------------------------------------------------------------------
723	    vc_slave : entity work.olo_test_axi_slave_vc
724	        generic map (
725	            Instance => AxiSlave_c
726	        )
727	        port map (
728	            Clk    => Clk,
729	            Axi_Ms => AxiMs,
730	            Axi_Sm => AxiSm
731	        );
732	
733	    vc_rd_data : entity vunit_lib.axi_stream_slave
734	        generic map (
735	            Slave => RdDataSlave_c
736	        )
737	        port map (
738	            AClk   => Clk,
739	            TValid => Rd_Valid,
740	            TReady => Rd_Ready,
741	            TData  => Rd_Data,
742	            TLast  => Rd_Last
743	        );
744	
745	    b_wr_cmd : block is
746	        signal TDataLocal : std_logic_vector(CmdLowLat_c downto 0);
747	    begin
748	
749	        vc_wr_cmd : entity vunit_lib.axi_stream_master
750	            generic map (
751	                Master => WrCmdMaster_c
752	            )
753	            port map (
754	                AClk   => Clk,
755	                TValid => CmdWr_Valid,
756	                TReady => CmdWr_Ready,
757	                TData  => TDataLocal
758	            );
759	
760	        CmdWr_Addr   <= TDataLocal(CmdAddrRange_c);
761	        CmdWr_Size   <= TDataLocal(CmdSizeRange_c);
762	        CmdWr_LowLat <= TDataLocal(CmdLowLat_c);
763	    end block;
764	
765	    b_rd_cmd : block is
766	        signal TDataLocal : std_logic_vector(CmdLowLat_c downto 0);
767	    begin
768	
769	        vc_rd_cmd : entity vunit_lib.axi_stream_master
770	            generic map (
771	                Master => RdCmdMaster_c
772	            )
773	            port map (
774	                AClk   => Clk,
775	                TValid => CmdRd_Valid,
776	                TReady => CmdRd_Ready,
777	                TData  => TDataLocal
778	            );
779	
780	        CmdRd_Addr   <= TDataLocal(CmdAddrRange_c);
781	        CmdRd_Size   <= TDataLocal(CmdSizeRange_c);
782	        CmdRd_LowLat <= TDataLocal(CmdLowLat_c);
783	    end block;
784	
785	    b_wr_data : block is
786	        signal TDataLocal : std_logic_vector(DatBeRange_c'high downto 0);
787	    begin
788	
789	        vc_wr_data : entity vunit_lib.axi_stream_master
790	            generic map (
791	                Master => WrDataMaster_c
792	            )
793	            port map (
794	                AClk   => Clk,
795	                TValid => Wr_Valid,
796	                TReady => Wr_Ready,
797	                TData  => TDataLocal
798	            );
799	
800	        Wr_Data <= TDataLocal(DatDataRange_c);
801	        Wr_Be   <= TDataLocal(DatBeRange_c);
802	    end block;
803	
804	end architecture;
